// Server-side data access. Reads the baked seed catalog/runs (generated by the
// Python engine) and combines them with live submitted runs to produce the
// leaderboard. Import this only from server components / route handlers.

import catalogJson from "@/data/catalog.json";
import arcadeJson from "@/data/arcade_catalog.json";
import runsJson from "@/data/runs.json";
import summaryJson from "@/data/summary.json";

import type { Game, RunRow, Summary, Task, Tier } from "./types";
import { buildLeaderboard } from "./scoring";
import { getSubmittedRuns } from "./store";
import { classifyAchievement, type TaskType } from "./taxonomy";

const STEAM_GAMES = (catalogJson as unknown as { games: Game[] }).games;
const ARCADE_GAMES = (arcadeJson as unknown as { games: Game[] }).games;
const SEED_RUNS = (runsJson as unknown as { runs: RunRow[] }).runs;
const SUMMARY = summaryJson as unknown as Summary;

// appid -> Game (both Steam and arcade)
const GAME_BY_APPID = new Map<number, Game>();
for (const g of [...ARCADE_GAMES, ...STEAM_GAMES]) GAME_BY_APPID.set(g.appid, g);

// appid -> Task[] for scoring runs.
const TASKS_BY_APPID = new Map<number, Task[]>();
for (const g of [...ARCADE_GAMES, ...STEAM_GAMES]) {
  if (g.tasks) TASKS_BY_APPID.set(g.appid, g.tasks);
}

const POP_WEIGHT = new Map<number, number>();
for (const g of [...ARCADE_GAMES, ...STEAM_GAMES])
  POP_WEIGHT.set(g.appid, g.appid >= 9000000 ? 1.2 : g.popularity_weight || 1);

export function getSteamGames(): Game[] {
  return STEAM_GAMES;
}

export function getArcadeGames(): Game[] {
  return ARCADE_GAMES;
}

export function getAllGames(): Game[] {
  return [...ARCADE_GAMES, ...STEAM_GAMES];
}

/** Lightweight game cards (no per-task arrays) for list views. */
export function getGameCards(): Game[] {
  return getAllGames().map(({ tasks, ...rest }) => rest);
}

export function getGame(appid: number): Game | undefined {
  return GAME_BY_APPID.get(appid);
}

export function getGameByEnvId(envId: string): Game | undefined {
  return ARCADE_GAMES.find((g) => g.env_id === envId);
}

export function getSummary(): Summary {
  return SUMMARY;
}

export function getTasksForApp(appid: number): Task[] {
  return TASKS_BY_APPID.get(appid) ?? [];
}

export interface AtlasTask extends Task {
  game: string;
  header: string;
}

/** Cross-game difficulty aggregation for the atlas view: the rarest
 * achievements across all Steam games, the hardest games to 100%, and the
 * population of every achievement by difficulty tier — all on the bits scale. */
export function getAtlas() {
  const steam = getSteamGames();
  const all: AtlasTask[] = [];
  for (const g of steam) {
    for (const t of g.tasks ?? []) {
      all.push({ ...t, game: g.name, header: g.header_image });
    }
  }
  const rarest = [...all].sort((a, b) => b.bits - a.bits).slice(0, 48);
  const hardestGames = [...steam]
    .filter((g) => g.num_achievements > 0)
    .sort((a, b) => b.total_bits - a.total_bits)
    .slice(0, 12);
  const tierTotals: Record<string, number> = {
    tutorial: 0, easy: 0, medium: 0, hard: 0, elite: 0, legendary: 0,
  };
  for (const t of all) tierTotals[t.tier] = (tierTotals[t.tier] ?? 0) + 1;
  return {
    rarest,
    hardestGames,
    tierTotals,
    totalTasks: all.length,
    totalGames: steam.length,
    totalBits: Math.round(all.reduce((n, t) => n + t.bits, 0)),
  };
}

export interface GradedTask {
  task_id: string;
  game_appid: number;
  name: string;
  game: string;
  header: string;
  rarity: number;
  bits: number;
  points: number;
  tier: Tier;
  type: TaskType;
  grade: number;
  reason: string;
}

/** Classify every Steam achievement by *what kind of task it is* (skill /
 * progression / grind / social / misc) and how well it discriminates skill — the
 * "which achievements make good benchmark tasks?" lens for the atlas. Additive:
 * does not affect scoring. */
export function getTaxonomy() {
  const steam = getSteamGames();
  const dist: Record<TaskType, number> = { skill: 0, progression: 0, grind: 0, social: 0, misc: 0 };
  const graded: GradedTask[] = [];
  for (const g of steam) {
    for (const t of g.tasks ?? []) {
      const c = classifyAchievement(t.name || t.source_ref || "", t.description || "", t.rarity);
      dist[c.type] += 1;
      graded.push({
        task_id: t.task_id, game_appid: t.game_appid, name: t.name || t.source_ref,
        game: g.name, header: g.header_image, rarity: t.rarity, bits: t.bits,
        points: t.points, tier: t.tier, type: c.type, grade: c.benchmarkGrade, reason: c.reason,
      });
    }
  }
  const total = graded.length;
  const topGraded = graded
    .filter((x) => x.type === "skill")
    .sort((a, b) => b.grade - a.grade || b.bits - a.bits)
    .slice(0, 24);
  return { dist, total, topGraded };
}

export async function getAllRuns(): Promise<RunRow[]> {
  const live = await getSubmittedRuns();
  return [...live, ...SEED_RUNS];
}

export async function getLeaderboard() {
  const runs = await getAllRuns();
  const { standings, humanVsAI } = buildLeaderboard(
    runs,
    TASKS_BY_APPID,
    (appid) => POP_WEIGHT.get(appid) ?? 1
  );
  return { standings, humanVsAI, totalRuns: runs.length };
}

/** Headline numbers for the landing hero. */
export async function getStats() {
  const lb = await getLeaderboard();
  const steam = getSteamGames();
  const totalSteamTasks = steam.reduce((n, g) => n + g.num_achievements, 0);
  const humans = lb.standings.filter((s) => s.kind === "human");
  const ais = lb.standings.filter((s) => s.kind === "agent");
  return {
    numSteamGames: steam.length,
    numArcadeGames: ARCADE_GAMES.length,
    totalSteamTasks,
    totalArcadeTasks: ARCADE_GAMES.reduce((n, g) => n + g.num_achievements, 0),
    numHumans: humans.length,
    numAgents: ais.length,
    totalRuns: lb.totalRuns,
    humanVsAI: lb.humanVsAI,
    topAgent: ais[0] ?? null,
    topHuman: humans[0] ?? null,
  };
}
